INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1128, 187236, 5, 1456, '悟', '曾经的都已经过去,不要再去试图从过去中施舍快乐.过去的就随意的将它抛弃在每个角落,不要去吝啬自己的过去,告诉自己过去的就随风而去,我的生命不要留连在过去,在时空的消失中.看见自己的身影,看见自己的面容,看见了热血在自己心中的涌东,看见了自己,看见了生命在此刻的停歇,让我明白了,我活着,活在现实的世界,活在今天,活在现在.为什么每个人在活着得时候不会真正得体会到活着得意义,到了对生命临别是又莫莫悲切了.为什么每个人都只会在失去时一味追逐不课得到得感觉,为什么我们都要那么冷漠得选择失去的美?为什么得不到的才会激起我们良心的愧疚了?为什么一生的情换不回一辈子的福了?为什么人要这么矛盾的活着,活着,用世俗的罪恶去净化自己纯真的心了?为什么寂寞和情总是纠缠不清了?为什么这个世界就只有男人和女人?为什么不给我们更多的机会去选择,为什么男女平等的背后隐藏着社会不负责任的唾弃?为什么这个社会已经失去了鲜活的空闲,以至于让我们这代不知所措.', '曾经的都已经过去,不要再去试图从过去中施舍快乐.过去的就随意的将它抛弃在每个角落,不要去吝啬自己的过去,告诉自己过去的就随风而去,我的生命不要留连在过去,在时空的消失中.看见自己的身影,看见自己的面容,看见了热血在自己心中的涌东,看见了自己,看见了生命在此刻的停歇,让我明白了,我活着,活在现实的世界,活在今天,活在现在.为什么每个人在活着得时候不会真正得体会到活着得意义,到了对生命临别是又莫莫悲切了.为什么每个人都只会在失去时一味追逐不课得到得感觉,为什么我们都要那么冷漠得选择失去的美?为什么得不到的才会激起我们良心的愧疚了?为什么一生的情换不回一辈子的福了?为什么人要这么矛盾的活着,活着,用世俗的罪恶去净化自己纯真的心了?为什么寂寞和情总是纠缠不清了?为什么这个世界就只有男人和女人?为什么不给我们更多的机会去选择,为什么男女平等的背后隐藏着社会不负责任的唾弃?为什么这个社会已经失去了鲜活的空闲,以至于让我们这代不知所措.', NULL, '2002-10-25 22:11:00', 2, '20021128033035_bbsid_187236_board_5_0448d8c69a.html', '20021128033035');
